window.addEventListener("load",()=>{const a=document.getElementById("header"),e=document.createElement("div");e.id="waymark-map",a.appendChild(e);const t=window.Waymark_Map_Factory.viewer();t.init({map_options:{tile_layers:[{layer_name:"OpenStreetMap",layer_url:"https://tiles.waymark.dev/osm/{z}/{x}/{y}.png",layer_attribution:'© <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',layer_max_zoom:"17"}],map_height:160,map_init_zoom:8,map_init_latlng:t.country_code_to_bounds().getCenter()}})});
